const MOCK_HEADER = "x-mock-request";

async function tryResolveRequestMockingProtocol(
  request: Request,
): Promise<Response | null> {
  const mockSchemas = await extractMockSchemas(async () => request.headers);
  if (!mockSchemas?.length) {
    return null;
  }

  const matchResult = await matchSchemas(request, mockSchemas);
  if (!matchResult) {
    return null;
  }

  const { body, headers, status, statusText } = await new ResponseBuilder(
    matchResult,
    {
      bypass: (req) => fetch(req),
    },
  ).build();

  return new Response(body, { status, statusText, headers });
}

