import { isOrgNextRequestMockingEnabled } from "@/lib/org-next-flags";

let installPromise: Promise<void> | undefined;

/**
 * When `VITE_ENABLE_RMP=true` (Playwright / e2e), install the package-supported
 * global `fetch` interceptor so SSR org API calls honor `x-mock-request` from
 * {@link https://github.com/vitalets/request-mocking-protocol request-mocking-protocol}.
 *
 * Uses the public `request-mocking-protocol/fetch` entry (not deep `dist/` paths).
 */
export async function ensureRequestMockingFetchInterceptor(): Promise<void> {
  if (!isOrgNextRequestMockingEnabled() || !import.meta.env.SSR) {
    return;
  }

  installPromise ??= (async () => {
    const [{ setupFetchInterceptor }, { getRequestHeaders }] = await Promise.all([
      import("request-mocking-protocol/fetch"),
      import("./tanstack-start-request-headers"),
    ]);
    setupFetchInterceptor(async () => getRequestHeaders());
  })();

  await installPromise;
}

import { isOrgNextBypassAuth } from "@/lib/org-next-flags";
import { readAuthenticatedAccessToken } from "./auth-session";

/**
 * Session token when logged in; otherwise a dev-only token when
 * `VITE_ORG_NEXT_BYPASS_AUTH=true` (local backend may ignore auth).
 */
export async function resolveOrgApiAccessToken(): Promise<string | null> {
  const fromSession = await readAuthenticatedAccessToken();
  if (fromSession) {
    return fromSession;
  }

  if (isOrgNextBypassAuth()) {
    const dev = import.meta.env.VITE_ORG_NEXT_DEV_ACCESS_TOKEN;
    return typeof dev === "string" ? dev : "";
  }

  return null;
}

import { resolveOrgApiAccessToken } from "./org-api-access-token";
import { ensureRequestMockingFetchInterceptor } from "./request-mocking-fetch-setup";
import { getServerOrgApiBaseUrl } from "./env";

export class OrgApiError extends Error {
  status: number;

  constructor(message: string, status: number) {
    super(message);
    this.name = "OrgApiError";
    this.status = status;
  }
}

type GetOrgApiJsonOptions = {
  accessToken: string;
};

type PostOrgApiJsonOptions<T> = {
  accessToken: string;
  path: string;
  payload: T;
};

async function requestOrgApiJson<T>(
  path: string,
  {
    accessToken,
    body,
    method = "GET",
  }: {
    accessToken: string;
    body?: unknown;
    method?: "GET" | "POST";
  },
): Promise<T> {
  await ensureRequestMockingFetchInterceptor();

  const hasBody = body !== undefined;

  const response = await fetch(new URL(path, getServerOrgApiBaseUrl()), {
    body: hasBody ? JSON.stringify(body) : undefined,
    headers: {
      Accept: "application/json",
      Authorization: `Bearer ${accessToken}`,
      ...(hasBody ? { "Content-Type": "application/json" } : {}),
      "X-APP": "anedot:3",
      "X-Api-Version": "1",
      "X-Requested-With": "XMLHttpRequest",
    },
    method,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new OrgApiError(
      errorText || `Request failed for ${path}`,
      response.status,
    );
  }

  return response.json() as Promise<T>;
}

export async function getOrgApiJson<T>(
  path: string,
  { accessToken }: GetOrgApiJsonOptions,
): Promise<T> {
  return requestOrgApiJson(path, { accessToken });
}

export async function postOrgApiJson<TPayload, TResponse>({
  accessToken,
  path,
  payload,
}: PostOrgApiJsonOptions<TPayload>): Promise<TResponse> {
  return requestOrgApiJson(path, {
    accessToken,
    body: payload,
    method: "POST",
  });
}

/** Convenience: resolve the session / dev token and call the org API. */
export async function getOrgApiJsonWithResolvedToken<T>(
  path: string,
): Promise<T> {
  const accessToken = await resolveOrgApiAccessToken();
  if (accessToken === null) {
    throw new OrgApiError("Not authenticated", 401);
  }
  return getOrgApiJson<T>(path, { accessToken });
}

export async function postOrgApiJsonWithResolvedToken<TPayload, TResponse>({
  path,
  payload,
}: {
  path: string;
  payload: TPayload;
}): Promise<TResponse> {
  const accessToken = await resolveOrgApiAccessToken();
  if (accessToken === null) {
    throw new OrgApiError("Not authenticated", 401);
  }
  return postOrgApiJson<TPayload, TResponse>({
    accessToken,
    path,
    payload,
  });
}

import type {
  OrgNextAppBootstrap,
  OrgNextTenant,
  OrgNextTenantMembership,
  OrgNextUser,
} from "@workspace/api-client/org-next";
import { resolveOrgApiAccessToken } from "./org-api-access-token";
import { getOrgApiJson } from "./org-api";

const pickCurrentUser = (users: OrgNextUser[], userId?: number) => {
  if (userId === undefined) {
    return users[0] ?? null;
  }

  return users.find((user) => user.id === userId) ?? null;
};

const pickAccessibleTenants = (
  tenants: OrgNextTenant[],
  memberships: OrgNextTenantMembership[],
) => {
  const tenantIds = new Set(
    memberships.map((membership) => membership.tenant_id),
  );

  return tenants.filter((tenant) => tenantIds.has(tenant.id));
};

const pickCurrentTenant = (
  accessibleTenants: OrgNextTenant[],
  tenantId?: number,
) => {
  if (tenantId === undefined) {
    return accessibleTenants[0] ?? null;
  }

  return (
    accessibleTenants.find((tenant) => tenant.id === tenantId) ?? null
  );
};

export async function getAppBootstrapData({
  tenantId,
  userId,
}: {
  tenantId?: number;
  userId?: number;
} = {}): Promise<OrgNextAppBootstrap | null> {
  const accessToken = await resolveOrgApiAccessToken();

  if (accessToken === null) {
    return null;
  }

  const [users, tenants, memberships] = await Promise.all([
    getOrgApiJson<OrgNextUser[]>("/users", { accessToken }),
    getOrgApiJson<OrgNextTenant[]>("/tenants", { accessToken }),
    getOrgApiJson<OrgNextTenantMembership[]>("/tenant_memberships", {
      accessToken,
    }),
  ]);

  const currentUser = pickCurrentUser(users, userId);
  const membershipsForUser = currentUser
    ? memberships.filter((membership) => membership.user_id === currentUser.id)
    : [];
  const accessibleTenants = pickAccessibleTenants(tenants, membershipsForUser);
  const currentTenant = pickCurrentTenant(accessibleTenants, tenantId);
  const currentMembership = currentTenant
    ? (membershipsForUser.find(
        (membership) => membership.tenant_id === currentTenant.id,
      ) ?? null)
    : (membershipsForUser[0] ?? null);

  return {
    accessibleTenants,
    currentMembership,
    currentTenant,
    currentUser,
    memberships: membershipsForUser,
    tenant: currentTenant,
    tenants,
    user:
      currentUser ??
      users[0] ??
      (() => {
        throw new Error("App bootstrap requires at least one user");
      })(),
    users,
  };
}

/** True when running with `VITE_ORG_NEXT_BYPASS_AUTH=true` (skip OAuth; use dev API token). */
export function isOrgNextBypassAuth(): boolean {
  return import.meta.env.VITE_ORG_NEXT_BYPASS_AUTH === "true";
}

/** Playwright e2e: global `fetch` honors `x-mock-request` (see `request-mocking-fetch-setup.ts`). */
export function isOrgNextRequestMockingEnabled(): boolean {
  return import.meta.env.VITE_ENABLE_RMP === "true";
}

/** Hardcoded user id for bootstrap when developing against a real local API. */
export function getOrgNextDevUserId(): number | undefined {
  const raw = import.meta.env.VITE_ORG_NEXT_DEV_USER_ID;
  if (raw === undefined || raw === "") {
    return undefined;
  }

  const n = Number.parseInt(String(raw), 10);
  return Number.isNaN(n) ? undefined : n;
}

import {
  type EmailAddress,
  makeEmailAddress,
  type OrgNextUser,
} from "@workspace/api-client/org-next";
import {
  getOrgApiJsonWithResolvedToken,
  postOrgApiJsonWithResolvedToken,
} from "./org-api";

export async function getUser({
  userId,
}: {
  userId?: string;
} = {}): Promise<OrgNextUser> {
  if (userId) {
    const user = await getOrgApiJsonWithResolvedToken<OrgNextUser>(
      `/users/${userId}`,
    );
    return user;
  }

  const user = await postOrgApiJsonWithResolvedToken<
    { user: { email: EmailAddress; cognito_sub: string } },
    OrgNextUser
  >({
    path: "/users",
    payload: {
      user: {
        email: makeEmailAddress("person@example.com"),
        cognito_sub: "abc-123",
      },
    },
  });
  return user;
}

import type {
  OrgNextTenant,
  OrgNextTenantCreateRequest,
} from "@workspace/api-client/org-next";
import {
  getOrgApiJsonWithResolvedToken,
  postOrgApiJsonWithResolvedToken,
} from "./org-api";

export async function getTenant({
  tenantId,
}: {
  tenantId: string;
}): Promise<OrgNextTenant> {
  const tenant = await getOrgApiJsonWithResolvedToken<OrgNextTenant>(
    `/tenants/${tenantId}`,
  );
  return tenant;
}

export async function createTenant(
  newTenant: OrgNextTenantCreateRequest,
): Promise<OrgNextTenant> {
  const tenant = await postOrgApiJsonWithResolvedToken<
    OrgNextTenantCreateRequest,
    OrgNextTenant
  >({
    path: "/tenants",
    payload: newTenant,
  });
  return tenant;
}

import { createFileRoute, Outlet, redirect } from "@tanstack/react-router";
import { getOrgNextDevUserId } from "@/lib/org-next-flags";

export const Route = createFileRoute("/_authed")({
  loader: async ({ location }) => {
    const { getAppBootstrapData } = await import("../server/app-bootstrap");
    const { OrgApiError } = await import("../server/org-api");

    try {
      const appBootstrap = await getAppBootstrapData({
        userId: getOrgNextDevUserId(),
      });

      if (!appBootstrap) {
        throw redirect({ to: "/login" });
      }

      const onWorkspaceNewRoute =
        location.pathname === "/workspace/new" ||
        location.pathname.endsWith("/workspace/new");

      if (appBootstrap.user && !appBootstrap.tenant && !onWorkspaceNewRoute) {
        throw redirect({ to: "/workspace/new" });
      }

      return appBootstrap;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      throw error;
    }
  },
  component: AuthedLayout,
});

function AuthedLayout() {
  return <Outlet />;
}

